#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode *next) : val(x), next(next) {}
};

class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        if (!head || !head->next) return head;
        ListNode* newHead = reverseList(head->next);
        head->next->next = head;
        head->next = nullptr;
        return newHead;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    ListNode dummy(0);
    ListNode* cur = &dummy;
    for (int i = 0; i < n; ++i) {
        int v; cin >> v;
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    ListNode* head = dummy.next;
    Solution sol;
    ListNode* rev = sol.reverseList(head);
    bool first = true;
    while (rev) {
        if (!first) cout << ' ';
        first = false;
        cout << rev->val;
        rev = rev->next;
    }
    cout << "\n";
    return 0;
}
